-- mig 342 — Q5 FY (gen_id 82) cleanup: replace v1-parser junk with new clean rows.
--   torque_specs: drop 105 v1 rows (notes='HaynesPro adjustmentData' from mig 341),
--                 insert 403 unique torques from new line-aware parser.
--   service_intervals: drop 33 interval-header rows from mig 341,
--                 insert 37 per-item rows mapped to snake_case codes.

SET NAMES utf8mb4;

-- 1. Resolve existing HaynesPro source ID
SET @s_haynes := (SELECT id FROM sources WHERE url = 'https://www.workshopdata.com/touch/site/layout/modelTypesList?modelId=d_319001449' ORDER BY id DESC LIMIT 1);

-- 2. DELETE v1 junk torque rows
DELETE ss FROM spec_sources ss JOIN torque_specs ts ON ts.id = ss.spec_id WHERE ss.spec_table = 'torque_specs' AND ts.generation_id = 82 AND ts.notes = 'HaynesPro adjustmentData';
DELETE FROM torque_specs WHERE generation_id = 82 AND notes = 'HaynesPro adjustmentData';

-- 3. DELETE v1 interval-header service rows
DELETE ss FROM spec_sources ss JOIN service_intervals si ON si.id = ss.spec_id WHERE ss.spec_table = 'service_intervals' AND si.generation_id = 82 AND si.notes LIKE 'HaynesPro modelDetailMaintenance%';
DELETE FROM service_intervals WHERE generation_id = 82 AND notes LIKE 'HaynesPro modelDetailMaintenance%';

-- 4. INSERT 403 clean torque rows

-- 5. INSERT 37 per-item service rows

-- 6. Citations

-- Audit
SELECT 'torque_specs' AS spec, COUNT(*) FROM torque_specs WHERE generation_id = 82 UNION ALL SELECT 'service_intervals', COUNT(*) FROM service_intervals WHERE generation_id = 82;